def _get_or_create_frequency(title: str) -> str:
    name = frappe.db.get_value("FT Frequency", {"frequency_title": title}, "name")
    if name:
        return name
    doc = frappe.get_doc({"doctype": "FT Frequency", "frequency_title": title})
    doc.insert(ignore_permissions=True)
    return doc.name


def _get_or_create_standard() -> str:
    name = frappe.db.get_value("FT Standard", {"standard_code": STANDARD_CODE}, "name")
    if not name:
        doc = frappe.get_doc(
            {
                "doctype": "FT Standard",
                "standard_code": STANDARD_CODE,
                "standard_label": STANDARD_LABEL,
                "standard_version": STANDARD_VERSION,
                "standard_description": STANDARD_DESC,
            }
        )
        doc.insert(ignore_permissions=True)
        return doc.name

    frappe.db.set_value(
        "FT Standard",
        name,
        {
            "standard_label": STANDARD_LABEL,
            "standard_version": STANDARD_VERSION,
            "standard_description": STANDARD_DESC,
        },
        update_modified=False,
    )
    return name


def _suite_code(table_id: str) -> str:
    return f"AS1851-T{table_id.replace('.', '-') }"


TABLE_LABELS = {
    "2.4.2.1": "AS1851 Monthly - Wet Pipe Systems",
    "2.4.2.2": "AS1851 Six-Monthly - Wet Pipe Systems",
    "2.4.2.3": "AS1851 Yearly - Wet Pipe Systems",
    "2.4.2.4": "AS1851 Five-Yearly - Wet Pipe Systems",
}


SECTION_SYSTEM_LABELS = {
    "2": "Wet Pipe Systems",
    "3": "Fire Pumpsets",
    "4": "Fire Hydrant Systems",
    "5": "Water Storage Tanks",
    "6": "Fire Detection and Alarm Systems",
    "7": "Special Hazard Systems",
    "8": "Occupant Warning Systems",
    "9": "Fire Hose Reels",
    "10": "Portable and Wheeled Fire Extinguishers",
    "11": "Fire Blankets",
    "12": "Passive Fire and Smoke Systems",
    "13": "Mechanical Services Smoke Control",
    "14": "Emergency Evacuation Systems",
}


def _infer_frequency(rows: list[dict], table_title: str = "") -> str:
    text = ((table_title or "") + " " + " ".join(((r.get("item", "") + " " + r.get("action", "")) for r in (rows or [])[:8]))).lower()
    if "thirty-yearly" in text:
        return "Thirty-Yearly"
    if "twenty-five" in text or "25-yearly" in text:
        return "Twenty-Five-Yearly"
    if "ten-yearly" in text:
        return "Ten-Yearly"
    if "five-yearly" in text:
        return "Five-Yearly"
    if "three-monthly" in text:
        return "Three-Monthly"
    if "six-monthly" in text:
        return "Six-Monthly"
    if "yearly" in text:
        return "Yearly"
    if "monthly" in text:
        return "Monthly"
    return "Monthly"


def _suite_label(table_id: str, rows: list[dict], table_title: str = "") -> str:
    if table_id in TABLE_LABELS:
        return TABLE_LABELS[table_id]
    section = table_id.split(".", 1)[0]
    system = SECTION_SYSTEM_LABELS.get(section, f"Table {table_id}")
    freq = _infer_frequency(rows, table_title)
    return f"AS1851 {freq} - {system}"

def _frequency_for_table(table_id: str) -> str:
    return "Monthly"

def _item_sort_key(item_no: str):
    parts = []
    for p in (item_no or "").split("."):
        try:
            parts.append(int(p))
        except Exception:
            parts.append(9999)
    return tuple(parts)

def _reading_meta(item: str, action: str):
    text = f"{item or ''} {action or ''}".lower()
    # Numeric capture/check keywords typically requiring entered readings.
    triggers = ("record", "measure", "pressure", "voltage", "current", "kpa", "seconds", "time")
    needs_reading = any(t in text for t in triggers)
    uom = None
    if "kpa" in text:
        uom = "kPa"
    elif "voltage" in text or re.search(r"\b v\b", text):
        uom = "V"
    elif "current" in text or re.search(r"\b a\b", text):
        uom = "A"
    elif "second" in text or re.search(r"\b s\b", text):
        uom = "s"
    return int(needs_reading), uom


def execute():
    std_name = _get_or_create_standard()
    frequency_cache = {}

    created = 0
    updated = 0

    existing = frappe.get_all("FT Test Suite", filters={"test_suite_code": ["like", "AS1851-T%"]}, pluck="name")
    for name in existing:
        frappe.delete_doc("FT Test Suite", name, force=1, ignore_permissions=True)
    legacy = frappe.db.get_value("FT Test Suite", {"test_suite_code": "AS1851-WET-MONTHLY"}, "name")
    if legacy:
        frappe.delete_doc("FT Test Suite", legacy, force=1, ignore_permissions=True)

    for table in TABLES:
        table_id = table["table_id"]
        rows = table.get("rows") or []
        table_title = (table.get("title") or "").strip()
        if not rows:
            continue

        freq_title = _infer_frequency(rows, table_title)
        freq_name = frequency_cache.get(freq_title)
        if not freq_name:
            freq_name = _get_or_create_frequency(freq_title)
            frequency_cache[freq_title] = freq_name

        code = _suite_code(table_id)
        label = _suite_label(table_id, rows, table_title)

        suite_name = frappe.db.get_value("FT Test Suite", {"test_suite_code": code}, "name")
        if suite_name:
            suite = frappe.get_doc("FT Test Suite", suite_name)
            updated += 1
        else:
            suite = frappe.get_doc({"doctype": "FT Test Suite"})
            created += 1

        suite.test_suite_code = code
        suite.test_suite_label = label
        suite.test_suite_standard = std_name
        suite.test_suite_frequency = freq_name
        suite.test_suite_table_ref = f"Table {table_id}"
        suite.test_suite_required_instrument = "None"
        suite.set("test_suite_items", [])

        rows_sorted = sorted(rows, key=lambda r: _item_sort_key((r.get("item_no") or "")))

        for row in rows_sorted:
            item_no = (row.get("item_no") or "").strip()
            item = (row.get("item") or "").strip()
            action = (row.get("action") or "").strip()
            if not item_no or not item:
                continue
            description = (f"{item}: {action}" if action else item)[:350]
            requires_reading, uom = _reading_meta(item, action)
            suite.append(
                "test_suite_items",
                {
                    "test_item_code": item_no,
                    "test_item_description": description,
                    "test_item_requires_reading": requires_reading,
                    "test_item_uom": uom,
                    "test_item_pass_required": 1,
                    "test_item_defect_on_fail": 1,
                },
            )

        if suite.name:
            suite.save(ignore_permissions=True)
        else:
            suite.insert(ignore_permissions=True)

    frappe.db.commit()
    frappe.logger().info(
        "AS1851 seed complete: created=%s updated=%s total_tables=%s",
        created,
        updated,
        len(TABLES),
    )
